Class Address Extends %RegisteredObject
{
    Property Street As %String;
    Property City As %String;
    Property State As %String;

    /// Get formatted full address
    Method GetFullAddress() As %String
    {
        // BUGGY: Doesn't handle null values - causes empty parts in output
        Set addr = ..Street _ ", " _ ..City _ ", " _ ..State
        Quit addr
    }
}

