Class TestAddress Extends %RegisteredObject
{
    ClassMethod TestGetFullAddress()
    {
        // Test with all values set
        Set addr = ##class(Address).%New()
        Set addr.Street = "123 Main St"
        Set addr.City = "Boston"
        Set addr.State = "MA"
        Set result = addr.GetFullAddress()
        If (result '= "123 Main St, Boston, MA") {
            Throw ##class(%Exception.General).%New("Full address failed: got "_result)
        }

        // Test with null city - should not have ", ," in output
        Set addr2 = ##class(Address).%New()
        Set addr2.Street = "456 Oak Ave"
        Set addr2.State = "CA"
        Set result2 = addr2.GetFullAddress()
        If (result2 [ ", ,") {
            Throw ##class(%Exception.General).%New("Should handle null city: got "_result2)
        }
    }
}
